// Define form schema with zod
const formSchema = z.object({
  name: z.string().min(2, { message: 'Name is required' }),
  email: z.string().email({ message: 'Invalid email address' }),
  phone: z.string().min(9, { message: 'Valid phone number is required' }),
  date: z.date({ required_error: 'Date is required' }),
  time: z.string().min(1, { message: 'Time is required' }),
  duration: z.string().min(1, { message: 'Duration is required' }),
  attendees: z.string().min(1, { message: 'Number of attendees is required' }),
  notes: z.string().optional(),
  termsAccepted: z.boolean().refine(val => val === true, { message: 'You must accept the terms' }),
});

interface ReservationFormProps {
  initialRoom?: string;
  initialDate?: string;
  initialTime?: string;
}

export function ReservationForm({ initialRoom, initialDate, initialTime }: ReservationFormProps) {
  const { locale } = useParams();
  const t = createTranslator(locale as string);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Initialize form
  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      name: '',
      email: '',
      phone: '',
      date: initialDate ? new Date(initialDate) : undefined,
      time: initialTime || '',
      duration: '1',
      attendees: '',
      notes: '',
      termsAccepted: false,
    },
  });

  // Set initial values if provided
  useEffect(() => {
    if (initialDate || initialTime) {
      form.reset({
        ...form.getValues(),
        date: initialDate ? new Date(initialDate) : form.getValues().date,
        time: initialTime || form.getValues().time,
      });
    }
  }, [initialDate, initialTime, form]);

  // Handle form submission
  const onSubmit = async (data: z.infer<typeof formSchema>) => {
    setIsSubmitting(true);
    setError(null);

    try {
      // TODO: Implement actual API submission
      console.log('Form data to submit:', data);

      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Show success message
      setIsSuccess(true);
      form.reset();
    } catch (err) {
      setError(t('reservation_error'));
      console.error('Reservation submission error:', err);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Generate time slots
  const timeSlots = [];
  for (let hour = 9; hour < 18; hour++) {
    const hourStr = hour.toString().padStart(2, '0');
