1. Create a breadcrumbs component with structured data:
```tsx
// components/breadcrumbs.tsx
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import Script from 'next/script';
import { createTranslator } from '@/paraglide/runtime';

interface BreadcrumbItem {
  name: string;
  href: string;
  translationKey?: string;
}

interface BreadcrumbsProps {
  items?: BreadcrumbItem[];
  locale: string;
}

export function Breadcrumbs({ items, locale }: BreadcrumbsProps) {
  const pathname = usePathname();
  const t = createTranslator(locale);

  // If no items are provided, generate them from the pathname
  const breadcrumbItems = items || generateBreadcrumbsFromPath(pathname, locale, t);

  // Add home as the first item
  const allItems = [
    { name: t('common.home'), href: '/' },
    ...breadcrumbItems,
  ];

  // Create structured data
  const breadcrumbsData = {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    itemListElement: allItems.map((item, index) => ({
      '@type': 'ListItem',
      position: index + 1,
      name: item.name,
      item: `https://deskohub.com${item.href === '/' ? '' : item.href}`,
    })),
  };

  return (
    <>
      <nav aria-label="Breadcrumbs" className="py-2">
        <ol className="flex items-center space-x-2 text-sm">
          {allItems.map((item, index) => (
            <li key={index} className="flex items-center">
              {index > 0 && <span className="mx-2 text-gray-400">/</span>}
              {index === allItems.length - 1 ? (
                <span className="text-gray-600">{item.name}</span>
              ) : (
                <Link href={item.href} className="text-blue-600 hover:underline">
                  {item.name}
                </Link>
              )}
            </li>
          ))}
        </ol>
      </nav>
      <Script
        id="breadcrumbs-structured-data"
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbsData) }}
      />
    </>
  );
}

// Helper function to generate breadcrumbs from path
function generateBreadcrumbsFromPath(pathname: string, locale: string, t: any) {
  const segments = pathname.split('/').filter(Boolean);

  // Remove locale from segments if present
  const pathSegments = segments[0] === locale ? segments.slice(1) : segments;

  // Map of path segments to translation keys
  const pathTranslations: Record<string, string> = {
    'coworking': 'nav.coworking',
    'training-rooms': 'nav.training_rooms',
    'about': 'nav.about',
    'contact': 'nav.contact',
    'pricing': 'nav.pricing',
    // Add more mappings as needed
  };

  return pathSegments.map((segment, index) => {
    const href = '/' + pathSegments.slice(0, index + 1).join('/');
    const translationKey = pathTranslations[segment];
    const name = translationKey ? t(translationKey) : segment.charAt(0).toUpperCase() + segment.slice(1).replace(/-/g, ' ');

    return { name, href };
  });
}
```

