```typescript
// app/api/auth/dotypos/logout/route.ts
import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  try {
    const authHeader = request.headers.get('Authorization');

    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return NextResponse.json({ error: 'Invalid authorization header' }, { status: 401 });
    }

    const token = authHeader.substring(7);

    // Call Dotypos revoke endpoint if they provide one
    // This is a placeholder - check Dotypos docs for actual revocation endpoint
    try {
      await fetch('https://api.dotypos.com/oauth/revoke', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          token,
          client_id: process.env.DOTYPOS_CLIENT_ID!,
          client_secret: process.env.DOTYPOS_CLIENT_SECRET!,
        }),
      });
    } catch (error) {
      console.error('Token revocation error:', error);
      // Continue with logout even if revocation fails
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Logout error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
