3. **Create Authentication Hook**:
```typescript
// hooks/use-dotypos-auth.ts
import { useState, useEffect, useCallback } from 'react';
import { dotyposAuth } from '@/services/auth/dotypos-auth.service';

export function useDotyposAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    // Check authentication status on mount
    setIsAuthenticated(dotyposAuth.isAuthenticated());
    setIsLoading(false);
  }, []);

  const login = useCallback(async (code: string): Promise<boolean> => {
    setIsLoading(true);
    try {
      const success = await dotyposAuth.login(code);
      setIsAuthenticated(success);
      return success;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const logout = useCallback(async (): Promise<void> => {
    setIsLoading(true);
    try {
      await dotyposAuth.logout();
      setIsAuthenticated(false);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const getAccessToken = useCallback(async (): Promise<string | null> => {
    return dotyposAuth.getAccessToken();
  }, []);

  return {
    isAuthenticated,
    isLoading,
    login,
    logout,
    getAccessToken,
  };
}
