// services/api/dotypos-api-client.ts
import { dotyposAuth } from '@/services/auth/dotypos-auth.service';

export class DotyposApiClient {
  private baseUrl: string;

  constructor(baseUrl: string = 'https://api.dotypos.com') {
    this.baseUrl = baseUrl;
  }

  private async getHeaders(): Promise<HeadersInit> {
    const token = await dotyposAuth.getAccessToken();

    if (!token) {
      throw new Error('Not authenticated');
    }

    return {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
    };
  }

  public async get<T>(endpoint: string): Promise<T> {
    try {
      const headers = await this.getHeaders();

      const response = await fetch(`${this.baseUrl}${endpoint}`, {
        method: 'GET',
        headers,
      });

      if (!response.ok) {
        throw new Error(`API request failed: ${response.statusText}`);
      }

      return await response.json() as T;
    } catch (error) {
      console.error(`GET ${endpoint} error:`, error);
      throw error;
    }
  }

  public async post<T>(endpoint: string, data: any): Promise<T> {
    try {
      const headers = await this.getHeaders();

      const response = await fetch(`${this.baseUrl}${endpoint}`, {
        method: 'POST',
        headers,
        body: JSON.stringify(data),
      });

      if (!response.ok) {
        throw new Error(`API request failed: ${response.statusText}`);
      }

      return await response.json() as T;
    } catch (error) {
      console.error(`POST ${endpoint} error:`, error);
      throw error;
    }
  }

  // Add other methods (PUT, DELETE, etc.) as needed
}

export const dotyposApiClient = new DotyposApiClient();
