global.fetch = jest.fn();

describe('DotyposAuthService', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockLocalStorage.clear();
  });

  test('should be a singleton', () => {
    const instance1 = DotyposAuthService.getInstance();
    const instance2 = DotyposAuthService.getInstance();
    expect(instance1).toBe(instance2);
  });

  test('should store and retrieve tokens correctly', () => {
    const service = DotyposAuthService.getInstance();
    const mockTokenResponse = {
      access_token: 'test_access_token',
      refresh_token: 'test_refresh_token',
      expires_in: 3600,
      token_type: 'Bearer'
    };

    // Mock JWT decode to return a specific expiration
    jest.mock('jwt-decode', () => ({
      jwtDecode: jest.fn().mockReturnValue({ exp: Math.floor(Date.now() / 1000) + 3600 })
    }));

    service.handleTokenResponse(mockTokenResponse);

    expect(service.isAuthenticated()).toBe(true);
    expect(service.getAccessToken()).resolves.toBe('test_access_token');

    // Verify tokens were saved to storage
    expect(mockLocalStorage.getItem('dotypos_tokens')).toBeTruthy();
  });

  test('should handle token expiration correctly', async () => {
    const service = DotyposAuthService.getInstance();

    // Set up expired token
    const expiredTime = Date.now() - 1000; // 1 second ago
    service.accessToken = 'expired_token';
    service.refreshToken = 'refresh_token';
    service.expiresAt = expiredTime;

    // Mock successful refresh
    (global.fetch as jest.Mock).mockResolvedValueOnce({
      ok: true,
      json: async () => ({
        access_token: 'new_access_token',
        refresh_token: 'new_refresh_token',
        expires_in: 3600
      })
    });

    // Mock JWT decode for the new token
    jest.mock('jwt-decode', () => ({
      jwtDecode: jest.fn().mockReturnValue({ exp: Math.floor(Date.now() / 1000) + 3600 })
    }));

    const token = await service.getAccessToken();

    expect(token).toBe('new_access_token');
    expect(global.fetch).toHaveBeenCalledWith('/api/auth/dotypos/refresh', expect.any(Object));
  });

  test('should handle refresh token failure', async () => {
    const service = DotyposAuthService.getInstance();

    // Set up expired token
    const expiredTime = Date.now() - 1000; // 1 second ago
    service.accessToken = 'expired_token';
    service.refreshToken = 'refresh_token';
    service.expiresAt = expiredTime;

    // Mock failed refresh
    (global.fetch as jest.Mock).mockResolvedValueOnce({
      ok: false,
      statusText: 'Unauthorized'
    });

    const token = await service.getAccessToken();

    expect(token).toBeNull();
    expect(service.isAuthenticated()).toBe(false);
  });
});
