// services/api/dotypos.service.ts
export class DotyposApiService {
  // ... existing code

  // Create reservation
  async createReservation(cloudId: string, data: ReservationCreateRequest): Promise<ReservationResponse> {
    const endpoint = this.getReservationsEndpoint(cloudId);
    return this.executeRequest<ReservationResponse>(endpoint, 'POST', data);
  }

  // Get single reservation
  async getReservation(cloudId: string, reservationId: string): Promise<ReservationResponse> {
    const endpoint = `${this.getReservationsEndpoint(cloudId)}/${reservationId}`;
    return this.executeRequest<ReservationResponse>(endpoint, 'GET');
  }

  // Update reservation
  async updateReservation(cloudId: string, reservationId: string, data: Partial<ReservationCreateRequest>): Promise<ReservationResponse> {
    const endpoint = `${this.getReservationsEndpoint(cloudId)}/${reservationId}`;
    const etag = this.getETag(reservationId);
    return this.executeRequest<ReservationResponse>(endpoint, 'PATCH', data, etag);
  }

  // Delete reservation
  async deleteReservation(cloudId: string, reservationId: string): Promise<void> {
    const endpoint = `${this.getReservationsEndpoint(cloudId)}/${reservationId}`;
    const etag = this.getETag(reservationId);
    await this.executeRequest<void>(endpoint, 'DELETE', undefined, etag);
  }
}
