import { DotyposReservationRequest } from '../../models/dotypos/reservation.model';

/**
 * Validates if a string is a valid ISO date format with timezone
 */
export function isValidISODateString(dateStr: string): boolean {
  try {
    const date = new Date(dateStr);
    return !isNaN(date.getTime()) && dateStr.includes('T') && 
           (dateStr.endsWith('Z') || /[+-]\d{2}:\d{2}$/.test(dateStr));
  } catch {
    return false;
  }
}

/**
 * Validates a Dotypos reservation payload
 * @returns Object with validation result and any error messages
 */
export function validateReservationPayload(payload: any): { valid: boolean; errors: string[] } {
  const errors: string[] = [];

  // Check required fields
  if (!payload.tableId) errors.push('Missing required field: tableId');
  if (!payload.startTime) errors.push('Missing required field: startTime');
  if (!payload.endTime) errors.push('Missing required field: endTime');
  if (payload.numberOfGuests === undefined) errors.push('Missing required field: numberOfGuests');
  if (!payload.status) errors.push('Missing required field: status');

  // Validate field formats
  if (payload.startTime && !isValidISODateString(payload.startTime)) {
    errors.push('Invalid startTime format. Use ISO 8601 format with timezone.');
  }
  if (payload.endTime && !isValidISODateString(payload.endTime)) {
    errors.push('Invalid endTime format. Use ISO 8601 format with timezone.');
  }
  if (payload.numberOfGuests !== undefined && 
      (typeof payload.numberOfGuests !== 'number' || payload.numberOfGuests <= 0)) {
    errors.push('numberOfGuests must be a positive number');
  }
  if (payload.status && 
      !['CONFIRMED', 'PENDING', 'CANCELLED'].includes(payload.status)) {
    errors.push('status must be one of: CONFIRMED, PENDING, CANCELLED');
  }

  // Add more validations based on API requirements

  return {
    valid: errors.length === 0,
    errors
  };
}

