   // src/lib/utils/time-formatter.ts

   /**
    * Converts a numeric hour value to a formatted time string
    * @param hour Numeric hour value (e.g., 17)
    * @param includeMinutes Whether to include ":00" in the output
    * @returns Formatted time string (e.g., "17:00")
    */
   export function formatHourToTimeString(hour: number, includeMinutes: boolean = true): string {
     if (hour < 0 || hour > 23) {
       throw new Error('Hour must be between 0 and 23');
     }

     return includeMinutes ? `${hour}:00` : `${hour}`;
   }

   /**
    * Parses a time string to extract the hour as a number
    * @param timeString Time string in format "HH:MM" (e.g., "17:00")
    * @returns Numeric hour value
    */
   export function parseTimeStringToHour(timeString: string): number {
     const match = timeString.match(/^(\d{1,2}):/);
     if (!match) {
       throw new Error('Invalid time string format. Expected "HH:MM"');
     }

     const hour = parseInt(match[1], 10);
     if (hour < 0 || hour > 23) {
       throw new Error('Hour must be between 0 and 23');
     }

     return hour;
   }
   ```

