   ```typescript
   // src/lib/utils/time-formatter.ts

   /**
    * Checks if the current time is within operating hours
    * @param openingHour Numeric opening hour
    * @param closingHour Numeric closing hour
    * @returns Boolean indicating if current time is within operating hours
    */
   export function isCurrentlyOpen(openingHour: number, closingHour: number): boolean {
     const now = new Date();
     const currentHour = now.getHours();
     return currentHour >= openingHour && currentHour < closingHour;
   }

   /**
    * Calculates hours until closing or opening
    * @param referenceHour The hour to compare against
    * @param isOpen Whether the business is currently open
    * @returns Number of hours until next state change
    */
   export function hoursUntilStateChange(referenceHour: number, isOpen: boolean): number {
     const now = new Date();
     const currentHour = now.getHours();

     return isOpen 
       ? (referenceHour - currentHour + 24) % 24 // Hours until closing
       : (referenceHour - currentHour + 24) % 24; // Hours until opening
   }
   ```

