2. **Explore Existing Email Service Infrastructure**:
   - Examine the email service in `/features/email/` to understand:
     - How the Resend provider is configured
     - Available email templates
     - Authentication and API key management
     - Error handling patterns

3. **Update Contact Service to Use Email Service**:
```typescript
// services/contact.service.ts
import { sendEmail } from '@/features/email/email.service';
import { ContactFormData } from '@/types/contact';

export async function submitContactForm(formData: ContactFormData): Promise<{ success: boolean; message: string }> {
  try {
    // Prepare email data from form submission
    const emailData = {
      to: process.env.CONTACT_FORM_RECIPIENT || 'info@deskohub.com',
      subject: `Contact Form: ${formData.subject || 'New Inquiry'}`,
      templateId: 'contact-form-notification',
      templateData: {
        name: formData.name,
        email: formData.email,
        phone: formData.phone || 'Not provided',
        subject: formData.subject || 'General Inquiry',
        message: formData.message,
        submittedAt: new Date().toISOString()
      }
    };

    // Send email using the email service
    const result = await sendEmail(emailData);

    // Return success response
    return {
      success: true,
      message: 'Your message has been sent successfully. We will get back to you soon.'
    };
  } catch (error) {
    console.error('Failed to send contact form email:', error);

    // Return error response
    return {
      success: false,
      message: 'Failed to send your message. Please try again later or contact us directly.'
    };
  }
}
```

