import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { getGames } from '@/lib/games/games-service';
import { GameCard } from '@/components/game-card';
import { createTranslator } from '@/paraglide/runtime';

export function GamesGalleryLoadMore({ locale }) {
  const t = createTranslator(locale);
  const [page, setPage] = useState(1);
  const [games, setGames] = useState([]);
  const [hasMore, setHasMore] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const pageSize = 24;

  const loadGames = async (pageNum = 1, append = false) => {
    setIsLoading(true);

    try {
      const data = await getGames({
        page: pageNum,
        pageSize
      });

      setGames(prev => append ? [...prev, ...data.games] : data.games);
      setHasMore(data.pagination.hasNextPage);
    } catch (error) {
      console.error('Failed to fetch games:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadGames(1, false);
  }, []);

  const handleLoadMore = () => {
    const nextPage = page + 1;
    setPage(nextPage);
    loadGames(nextPage, true);
  };

  return (
    <div className="w-full">
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
        {games.map(game => (
          <GameCard key={game.id} game={game} locale={locale} />
        ))}
      </div>

      {hasMore && (
        <div className="flex justify-center mt-8">
          <Button 
            onClick={handleLoadMore} 
            disabled={isLoading}
            size="lg"
          >
            {isLoading ? (
              <>
                <LoadingSpinner className="mr-2 h-4 w-4" />
                {t('games.loading')}
              </>
            ) : (
              t('games.loadMore')
            )}
          </Button>
        </div>
      )}
    </div>
  );
}

