## Objective
Implement a responsive and accessible lightbox component for gallery images that allows users to view full-size images and navigate through photo collections.

## Implementation Steps

1. **Select and Install a Lightbox Library**:
   ```bash
   npm install yet-another-react-lightbox
   # Optional plugins for additional features
   npm install yet-another-react-lightbox/plugins/thumbnails
   npm install yet-another-react-lightbox/plugins/zoom
   npm install yet-another-react-lightbox/plugins/counter
   ```

2. **Create a Reusable Lightbox Component**:
   ```tsx
   // components/ui/lightbox.tsx
   import { useState } from 'react';
   import Lightbox from 'yet-another-react-lightbox';
   import Thumbnails from 'yet-another-react-lightbox/plugins/thumbnails';
   import Zoom from 'yet-another-react-lightbox/plugins/zoom';
   import Counter from 'yet-another-react-lightbox/plugins/counter';
   import 'yet-another-react-lightbox/styles.css';
   import 'yet-another-react-lightbox/plugins/thumbnails.css';
   import 'yet-another-react-lightbox/plugins/counter.css';

   interface LightboxProps {
     images: Array<{
       src: string;
       alt?: string;
       width?: number;
       height?: number;
     }>;
     open: boolean;
     index: number;
     onClose: () => void;
   }

   export function ImageLightbox({ images, open, index, onClose }: LightboxProps) {
     return (
       <Lightbox
         open={open}
         close={onClose}
         index={index}
         slides={images}
         plugins={[Thumbnails, Zoom, Counter]}
         carousel={{ finite: images.length <= 1 }}
         render={{
           buttonPrev: images.length <= 1 ? () => null : undefined,
           buttonNext: images.length <= 1 ? () => null : undefined,
         }}
       />
     );
   }
   ```

