4. **Update Template Service Implementation**:
```typescript
// services/template-service.ts
import fs from 'fs/promises';
import path from 'path';
import Handlebars from 'handlebars';

// Cache for compiled templates
const templateCache = new Map<string, Handlebars.TemplateDelegate>();

/**
 * Loads and compiles a template if not already in cache
 */
async function getCompiledTemplate(templateName: string): Promise<Handlebars.TemplateDelegate> {
  if (templateCache.has(templateName)) {
    return templateCache.get(templateName)!;
  }

  const templatePath = path.join(process.cwd(), 'templates', `${templateName}.html`);
  const templateContent = await fs.readFile(templatePath, 'utf-8');
  const compiledTemplate = Handlebars.compile(templateContent);

  templateCache.set(templateName, compiledTemplate);
  return compiledTemplate;
}

/**
 * Renders an email template with the provided data
 */
export async function renderEmailTemplate(templateName: string, data: any): Promise<string> {
  try {
    const template = await getCompiledTemplate(templateName);

    // Add common template data
    const templateData = {
      ...data,
      logoUrl: 'https://deskohub.com/images/logo.png',
      currentYear: new Date().getFullYear(),
      address: 'Deskohub, Example Street 123, Prague, Czech Republic',
      contactEmail: 'info@deskohub.com',
      contactPhone: '+420 123 456 789'
    };

    return template(templateData);
  } catch (error) {
    console.error(`Error rendering template ${templateName}:`, error);
    // Fallback to JSON dump in case of error
    return `<pre>${JSON.stringify(data, null, 2)}</pre>`;
  }
}

/**
 * Gets the appropriate template name for a given email type
 */
export function getTemplateNameForEmailType(emailType: string): string {
  switch (emailType) {
    case 'reservation-confirmation':
      return 'reservation-confirmation';
    case 'contact-form-submission':
      return 'contact-form-submission';
    case 'training-room-booking':
      return 'training-room-booking';
    // Add more email types as needed
    default:
      return 'base-email';
  }
}
```

