// services/email-service.ts
import { renderEmailTemplate, getTemplateNameForEmailType } from './template-service';
import { sendEmail } from './resend-provider'; // Assuming this is the actual email sending service

/**
 * Sends an email using the appropriate template
 */
export async function sendTemplatedEmail(
  emailType: string,
  to: string,
  subject: string,
  data: any
): Promise<boolean> {
  try {
    const templateName = getTemplateNameForEmailType(emailType);
    const htmlContent = await renderEmailTemplate(templateName, data);

    // Send the email with the rendered HTML content
    await sendEmail({
      to,
      subject,
      html: htmlContent,
      from: 'noreply@deskohub.com',
      replyTo: 'info@deskohub.com'
    });

    return true;
  } catch (error) {
    console.error('Error sending templated email:', error);
    return false;
  }
}
```

