// SEO metadata generation
export async function generateMetadata({ params }): Promise<Metadata> {
  const { locale } = params;
  const t = createTranslator(locale);

  return {
    title: t('admin.dashboard.title', 'Admin Dashboard - Deskohub'),
    description: t('admin.dashboard.description', 'Administrative dashboard for Deskohub management'),
    robots: 'noindex, nofollow' // Prevent indexing of admin pages
  };
}

export default async function AdminDashboardPage({ params }) {
  const { locale } = params;
