## Objective
Create a comprehensive admin interface for managing table reservations with approval workflows, detailed views, and email integration.

## Implementation Steps

1. **Create Protected Admin Route Structure**:
```typescript
// app/[locale]/admin/reservations/page.tsx
import { createTranslator } from '@/paraglide/runtime';
import { redirect } from 'next/navigation';
import { AdminHeader } from '@/components/admin/admin-header';
import { ReservationList } from '@/components/admin/reservation-list';
import { getServerSession } from 'next-auth/next';
import { authOptions } from '@/lib/auth';
import { Metadata } from 'next';

export async function generateMetadata({ params }): Promise<Metadata> {
  const { locale } = params;
  const t = createTranslator(locale);

  return {
    title: t('admin.reservations.title'),
    description: t('admin.reservations.description'),
  };
}

export default async function AdminReservationsPage({ params }) {
  const { locale } = params;
  const t = createTranslator(locale);
  const session = await getServerSession(authOptions);

  // Redirect to login if not authenticated
  if (!session) {
    redirect(`/${locale}/auth/login?callbackUrl=/${locale}/admin/reservations`);
  }

  // Check if user has admin role
  if (!session.user.roles?.includes('admin')) {
    redirect(`/${locale}/`);
  }

  return (
    <div className="container mx-auto py-8">
      <AdminHeader 
        title={t('admin.reservations.pageTitle')} 
        description={t('admin.reservations.pageDescription')} 
      />
      <ReservationList locale={locale} />
    </div>
  );
}
```

