3. **Create Reservation List Component with Filtering**:
```typescript
// components/admin/reservation-list.tsx
import { useState } from 'react';
import { createTranslator } from '@/paraglide/runtime';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { DataTable } from '@/components/ui/data-table';
import { useDotyposReservations } from '@/hooks/use-dotypos-reservations';
import { Badge } from '@/components/ui/badge';
import { formatDate, formatTime } from '@/lib/utils/date';
import Link from 'next/link';
import { Search, Filter } from 'lucide-react';

interface ReservationListProps {
  locale: string;
}

export function ReservationList({ locale }: ReservationListProps) {
  const t = createTranslator(locale);
  const [filters, setFilters] = useState({
    status: 'pending',
    search: '',
    dateFrom: '',
    dateTo: '',
  });

  const { reservations, isLoading, error } = useDotyposReservations(filters);

  const columns = [
    {
      accessorKey: 'id',
      header: t('admin.reservations.columns.id'),
    },
    {
      accessorKey: 'customerName',
      header: t('admin.reservations.columns.customer'),
    },
    {
      accessorKey: 'date',
      header: t('admin.reservations.columns.date'),
      cell: ({ row }) => formatDate(row.original.date, locale),
    },
    {
      accessorKey: 'time',
      header: t('admin.reservations.columns.time'),
      cell: ({ row }) => formatTime(row.original.time, locale),
    },
    {
      accessorKey: 'partySize',
      header: t('admin.reservations.columns.partySize'),
    },
    {
      accessorKey: 'status',
      header: t('admin.reservations.columns.status'),
      cell: ({ row }) => (
        <Badge variant={getBadgeVariant(row.original.status)}>
          {t(`admin.reservations.status.${row.original.status}`)}
        </Badge>
      ),
    },
    {
      id: 'actions',
      cell: ({ row }) => (
        <Link href={`/${locale}/admin/reservations/${row.original.id}`}>
          <Button variant="outline" size="sm">
            {t('admin.reservations.viewDetails')}
          </Button>
        </Link>
      ),
    },
  ];

  function getBadgeVariant(status) {
    switch (status) {
      case 'pending': return 'warning';
      case 'approved': return 'success';
      case 'denied': return 'destructive';
      default: return 'secondary';
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>{t('admin.reservations.listTitle')}</CardTitle>
        <div className="flex flex-col md:flex-row gap-4 mt-4">
          <div className="relative flex-1">
            <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder={t('admin.reservations.searchPlaceholder')}
              className="pl-8"
              value={filters.search}
              onChange={(e) => setFilters({ ...filters, search: e.target.value })}
            />
          </div>
          <Select
            value={filters.status}
            onValueChange={(value) => setFilters({ ...filters, status: value })}
          >
            <SelectTrigger className="w-full md:w-[180px]">
              <SelectValue placeholder={t('admin.reservations.statusFilter')} />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">{t('admin.reservations.status.all')}</SelectItem>
              <SelectItem value="pending">{t('admin.reservations.status.pending')}</SelectItem>
              <SelectItem value="approved">{t('admin.reservations.status.approved')}</SelectItem>
              <SelectItem value="denied">{t('admin.reservations.status.denied')}</SelectItem>
            </SelectContent>
          </Select>
          <div className="flex gap-2">
            <Input
              type="date"
              value={filters.dateFrom}
              onChange={(e) => setFilters({ ...filters, dateFrom: e.target.value })}
              className="w-full md:w-[150px]"
            />
            <Input
              type="date"
              value={filters.dateTo}
              onChange={(e) => setFilters({ ...filters, dateTo: e.target.value })}
              className="w-full md:w-[150px]"
            />
          </div>
        </div>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <div className="flex justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
          </div>
        ) : error ? (
          <div className="text-center py-8 text-destructive">
            {t('admin.reservations.loadError')}
          </div>
        ) : (
          <DataTable
            columns={columns}
            data={reservations}
            emptyMessage={t('admin.reservations.noReservations')}
          />
        )}
      </CardContent>
    </Card>
  );
}
```

4. **Create Reservation Detail Component with Approve/Deny Actions**:
```typescript
// components/admin/reservation-detail.tsx
import { useState } from 'react';
import { createTranslator } from '@/paraglide/runtime';
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { useDotyposReservation } from '@/hooks/use-dotypos-reservation';
import { updateReservationStatus } from '@/lib/dotypos/reservation-service';
import { formatDate, formatTime } from '@/lib/utils/date';
import { useToast } from '@/components/ui/use-toast';
import { AlertCircle, Check, X, ArrowLeft } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

interface ReservationDetailProps {
  id: string;
  locale: string;
}

export function ReservationDetail({ id, locale }: ReservationDetailProps) {
  const t = createTranslator(locale);
  const { toast } = useToast();
  const router = useRouter();
  const { reservation, isLoading, error, mutate } = useDotyposReservation(id);
  const [isUpdating, setIsUpdating] = useState(false);

  async function handleStatusUpdate(status: 'approved' | 'denied') {
    try {
      setIsUpdating(true);
      await updateReservationStatus(id, status);
      await mutate();
      toast({
        title: t('admin.reservations.statusUpdateSuccess'),
        description: t(`admin.reservations.${status}Success`),
      });
    } catch (error) {
      console.error('Failed to update reservation status:', error);
      toast({
        title: t('admin.reservations.statusUpdateError'),
        description: t('admin.reservations.statusUpdateErrorDescription'),
        variant: 'destructive',
      });
    } finally {
      setIsUpdating(false);
    }
  }

  function getBadgeVariant(status) {
