// lib/dotypos/reservation-service.ts
import { dotyposApiClient } from './api-client';

export interface ReservationFilters {
  status?: string;
  search?: string;
  dateFrom?: string;
  dateTo?: string;
}

export async function getReservations(filters: ReservationFilters = {}) {
  try {
    const queryParams = new URLSearchParams();

    if (filters.status && filters.status !== 'all') {
      queryParams.append('status', filters.status);
    }

    if (filters.search) {
      queryParams.append('search', filters.search);
    }

    if (filters.dateFrom) {
      queryParams.append('dateFrom', filters.dateFrom);
    }

    if (filters.dateTo) {
      queryParams.append('dateTo', filters.dateTo);
    }

    const response = await dotyposApiClient.get(`/reservations?${queryParams.toString()}`);
    return response.data;
  } catch (error) {
    console.error('Failed to fetch reservations:', error);
    throw error;
  }
}

export async function getReservationById(id: string) {
  try {
    const response = await dotyposApiClient.get(`/reservations/${id}`);
    return response.data;
  } catch (error) {
    console.error(`Failed to fetch reservation with ID ${id}:`, error);
    throw error;
  }
}

export async function updateReservationStatus(id: string, status: 'approved' | 'denied') {
  try {
    const response = await dotyposApiClient.patch(`/reservations/${id}`, {
      status,
      timestamp: new Date().toISOString(),
    });
    return response.data;
  } catch (error) {
    console.error(`Failed to update reservation status for ID ${id}:`, error);
    throw error;
  }
}
