Create utility functions in `backend/features/webhooks/utils/signature-utils.ts`:

```typescript
import crypto from 'crypto';

/**
 * Generate a signature for webhook payload
 */
export function generateSignature(payload: unknown, secret: string): string {
  const hmac = crypto.createHmac('sha256', secret);
  hmac.update(JSON.stringify(payload));
  return hmac.digest('hex');
}

/**
 * Verify webhook signature
 */
export function verifySignature(
  payload: unknown,
  signature: string,
  secret: string
): boolean {
  const expectedSignature = generateSignature(payload, secret);
  return crypto.timingSafeEqual(
    Buffer.from(signature),
    Buffer.from(expectedSignature)
  );
}

/**
 * Generate a random webhook secret
 */
export function generateWebhookSecret(): string {
  return crypto.randomBytes(24).toString('hex');
}

/**
 * Create a webhook signature header
 */
export function createSignatureHeader(payload: unknown, secret: string): string {
  const timestamp = Date.now().toString();
  const signature = generateSignature(payload, secret);
  return `t=${timestamp},v1=${signature}`;
}

/**
 * Parse and verify a webhook signature header
 */
export function parseAndVerifySignatureHeader(
  header: string,
  payload: unknown,
  secret: string
): boolean {
  const parts = header.split(',');
  const signaturePart = parts.find(part => part.startsWith('v1='));

  if (!signaturePart) {
    return false;
  }

  const signature = signaturePart.substring(3);
  return verifySignature(payload, signature, secret);
}
```

