import { db } from '@/lib/db';
import { WebhookPayload, WebhookConfig } from '../schemas/webhook-schema';
import { WebhookError, WebhookDeliveryError } from '../errors/webhook-error';
import { generateSignatureHeader, generateWebhookSecret } from '../utils/signature-utils';
import axios from 'axios';

export class WebhookService {
  /**
   * Register a new webhook endpoint
   */
  async registerWebhook(config: WebhookConfig): Promise<string> {
    try {
      const webhook = await db.webhook.create({
        data: {
          url: config.url,
          events: config.events,
          secret: config.secret || generateWebhookSecret(),
          description: config.description,
          isActive: true,
          createdAt: new Date(),
        },
      });

      return webhook.id;
    } catch (error) {
      throw new WebhookError('Failed to register webhook', error);
    }
  }

  /**
   * Trigger webhook for a specific event
   */
  async triggerWebhook(event: string, payload: WebhookPayload): Promise<void> {
    try {
      // Find all webhooks subscribed to this event
      const webhooks = await db.webhook.findMany({
        where: {
          events: { has: event },
          isActive: true
        },
      });

      // Send the webhook to each subscriber
      const deliveryPromises = webhooks.map(async (webhook) => {
        try {
          const signatureHeader = generateSignatureHeader(payload, webhook.secret);

          // Record the delivery attempt
          const delivery = await db.webhookDelivery.create({
            data: {
              webhookId: webhook.id,
              event,
              payload,
              status: 'pending',
              createdAt: new Date()
            }
          });

          // Send the webhook
          const response = await axios.post(webhook.url, payload, {
            headers: {
              'Content-Type': 'application/json',
              'X-Webhook-Signature': signatureHeader
            },
            timeout: 5000 // 5 second timeout
          });

          // Update delivery status
          await db.webhookDelivery.update({
            where: { id: delivery.id },
            data: {
              status: 'success',
              response: response.data
            }
          });
        } catch (error) {
          // Record failed delivery
          await db.webhookDelivery.update({
            where: { id: delivery.id },
            data: {
              status: 'failed',
              response: { error: error.message }
            }
          });

          throw new WebhookDeliveryError(
            webhook.id,
            event,
            `Failed to deliver webhook to ${webhook.url}`,
            error
          );
        }
      });

      // Wait for all deliveries to complete, but don't fail if some fail
      await Promise.allSettled(deliveryPromises);
    } catch (error) {
      throw new WebhookError(`Failed to trigger webhooks for event ${event}`, error);
    }
  }

  /**
   * Get all registered webhooks
   */
  async getWebhooks(): Promise<WebhookConfig[]> {
    try {
      const webhooks = await db.webhook.findMany({
        orderBy: { createdAt: 'desc' }
      });

      return webhooks.map(webhook => ({
        url: webhook.url,
        events: webhook.events,
        secret: webhook.secret,
        description: webhook.description
      }));
    } catch (error) {
      throw new WebhookError('Failed to retrieve webhooks', error);
    }
  }

  /**
   * Delete a webhook by ID
   */
  async deleteWebhook(id: string): Promise<boolean> {
    try {
      await db.webhook.delete({
        where: { id }
      });

      return true;
    } catch (error) {
      throw new WebhookError(`Failed to delete webhook with ID ${id}`, error);
    }
  }

  /**
   * Update webhook active status
   */
  async updateWebhookStatus(id: string, isActive: boolean): Promise<boolean> {
    try {
      await db.webhook.update({
        where: { id },
        data: { isActive }
      });

      return true;
    } catch (error) {
      throw new WebhookError(`Failed to update webhook status for ID ${id}`, error);
    }
  }
}
```

