  branchid: E.schema.string,
  created: E.schema.string.pipe(E.schema.dateFromString),
  customerid: E.schema.string,
  employeeid: E.schema.string.pipe(E.schema.nullable),
  flags: E.schema.array(E.schema.string),
  deleted: E.schema.boolean,
  note: E.schema.string.pipe(E.schema.nullable),
