  tableid: E.schema.string,
  taglist: E.schema.array(E.schema.string),
  versiondate: E.schema.string.pipe(E.schema.dateFromString),
  reservationid: E.schema.string,
  startdate: E.schema.string.pipe(E.schema.dateFromString),
  enddate: E.schema.string.pipe(E.schema.dateFromString),
  cloudid: E.schema.string
});

