Create a robust webhook validation service using Effect.ts patterns to ensure secure processing of incoming webhooks with proper validation, authentication, and error handling.

## Implementation Steps

1. **Create Webhook Validation Service Module**:
```typescript
// backend/features/webhooks/services/webhook-validation.service.ts
import { Effect as E } from "effect";
import { WebhookSecretNotFoundError, InvalidWebhookSignatureError, InvalidPayloadError } from "../errors/webhook-errors";
import * as Schemas from "../schemas/effect";

/**
 * Service for validating incoming webhooks
 */
export const WebhookValidationService = {
  /**
   * Validates a webhook request including signature and payload
   */
  validateWebhook: <T>(
    payload: unknown, 
    signature: string | undefined, 
    schema: E.Schema<T>, 
    secretKey: string
  ): E.Effect<never, WebhookSecretNotFoundError | InvalidWebhookSignatureError | InvalidPayloadError, T> => {
    return E.gen(function* (_) {
      // Verify webhook signature exists
      if (!signature) {
        return yield* _(E.fail(new InvalidWebhookSignatureError("Missing webhook signature")));
      }

      // Verify secret key exists
      if (!secretKey) {
        return yield* _(E.fail(new WebhookSecretNotFoundError("Webhook secret not found")));
      }

      // Verify signature
      yield* _(verifySignature(payload, signature, secretKey));

      // Validate payload against schema
      return yield* _(validatePayload(payload, schema));
    });
  }
};

/**
 * Verifies the webhook signature using HMAC
 */
const verifySignature = (
  payload: unknown, 
  signature: string, 
  secretKey: string
): E.Effect<never, InvalidWebhookSignatureError, void> => {
  return E.gen(function* (_) {
    try {
      const crypto = require('crypto');
      const hmac = crypto.createHmac('sha256', secretKey);
      const payloadString = typeof payload === 'string' ? payload : JSON.stringify(payload);
      const calculatedSignature = hmac.update(payloadString).digest('hex');

      // Use constant-time comparison to prevent timing attacks
      const isValid = crypto.timingSafeEqual(
        Buffer.from(calculatedSignature, 'hex'),
        Buffer.from(signature, 'hex')
      );

      if (!isValid) {
        return yield* _(E.fail(new InvalidWebhookSignatureError("Invalid webhook signature")));
      }
    } catch (error) {
      return yield* _(E.fail(new InvalidWebhookSignatureError(`Error verifying signature: ${error.message}`)));
    }
  });
};

/**
 * Validates the payload against the provided schema
 */
const validatePayload = <T>(
  payload: unknown, 
  schema: E.Schema<T>
): E.Effect<never, InvalidPayloadError, T> => {
  return E.gen(function* (_) {
    const result = E.try({
      try: () => E.decodeUnknown(schema)(payload),
      catch: (error) => new InvalidPayloadError(`Invalid payload: ${E.pretty(error)}`)
    });

    return yield* _(result);
  });
};
```

