4. **Create Webhook Handler Using the Service**:
```typescript
// backend/features/webhooks/handlers/webhook-handler.ts
import { Effect as E } from "effect";
import { WebhookService } from "../services/webhook-service";
import { WebhookValidationService } from "../services/webhook-validation.service";
import { DotyposReservationPayload } from "../schemas/effect";

/**
 * Handler for Dotypos reservation webhooks
 */
export const handleDotyposReservationWebhook = (
  payload: unknown,
  signature: string
) => {
  return E.gen(function* (_) {
    // Get services from context
    const validationService = yield* _(WebhookValidationService);
    const webhookService = yield* _(WebhookService);

    // Validate the webhook
    const validatedPayload = yield* _(
      validationService.validateWebhook(payload, signature, "dotypos")
    );

    // Process the webhook
    yield* _(webhookService.processDotyposReservation(
      validatedPayload as DotyposReservationPayload
    ));

    return { success: true };
  });
};

/**
 * Handler for contact form webhooks
 */
export const handleContactFormWebhook = (
  payload: unknown,
  signature: string
) => {
  return E.gen(function* (_) {
    // Get services from context
    const validationService = yield* _(WebhookValidationService);
    const webhookService = yield* _(WebhookService);

    // Validate the webhook
    const validatedPayload = yield* _(
      validationService.validateWebhook(payload, signature, "contact")
    );

    // Process the webhook
    yield* _(webhookService.processContactForm(validatedPayload));

    return { success: true };
  });
};
```

5. **Create Layer Composition for Application**:
```typescript
// backend/features/webhooks/layers.ts
import { Layer } from "effect";
import { WebhookServiceLive } from "./services/webhook-service.live";
import { WebhookValidationServiceLive } from "./services/webhook-validation.service";
import { DotyposServiceLive } from "@/backend/features/dotypos/services/dotypos-service.live";
import { EmailServiceLive } from "@/backend/features/email/services/email-service.live";

/**
 * Combined layer for webhook processing
 */
export const WebhookLayer = WebhookServiceLive.pipe(
  Layer.provide(WebhookValidationServiceLive),
  Layer.provide(DotyposServiceLive),
  Layer.provide(EmailServiceLive)
);
```

6. **Integrate with API Route**:
```typescript
// app/api/webhooks/dotypos/route.ts
import { NextRequest, NextResponse } from "next/server";
import { Effect as E, Runtime } from "effect";
import { handleDotyposReservationWebhook } from "@/backend/features/webhooks/handlers/webhook-handler";
import { WebhookLayer } from "@/backend/features/webhooks/layers";

export async function POST(request: NextRequest) {
  try {
    const payload = await request.json();
    const signature = request.headers.get("x-webhook-signature") || "";

    // Create runtime with all required layers
    const runtime = Runtime.make(WebhookLayer);

    // Run the webhook handler
    const result = await runtime.runPromise(
      handleDotyposReservationWebhook(payload, signature)
    );

    return NextResponse.json(result, { status: 200 });
  } catch (error) {
    console.error("Webhook processing error:", error);
    return NextResponse.json(
      { error: "Failed to process webhook" },
      { status: 500 }
    );
  }
}
```

