## Objective
Create a robust ReservationWebhookHandler that processes incoming webhook events for reservation status changes with proper Effect.ts patterns, email notifications, and comprehensive error handling.

## Implementation Steps

1. **Create ReservationWebhookHandler Module**:
```typescript
// backend/features/webhooks/handlers/reservation-webhook.handler.ts
import { Effect as E } from "effect";
import { WebhookService } from "../services/webhook-service";
import { DotyposReservationPayload } from "../schemas/effect";
import { EmailService } from "@/backend/features/email/services/email-service";
import { ReservationStatusEnum } from "../schemas/effect";
import { WebhookProcessingError } from "../errors/webhook-errors";

/**
 * Handler for processing reservation webhook events
 */
export const ReservationWebhookHandler = {
  /**
   * Process a reservation status change webhook
   */
  processReservationStatusChange: (payload: DotyposReservationPayload) =>
    E.gen(function* (_) {
      const webhookService = yield* _(WebhookService);
      const emailService = yield* _(EmailService);

      // Extract reservation data
      const { reservationId, status, customerInfo, reservationDetails } = payload;

      // Log the incoming webhook
      yield* _(E.logInfo("Processing reservation status change webhook", { 
        reservationId, 
        status 
      }));

      // Process based on status
      switch (status) {
        case ReservationStatusEnum.CREATED:
          // Store the new reservation
          yield* _(webhookService.storeReservation(payload));

          // Send notification to admin
          yield* _(emailService.sendAdminReservationNotification({
            reservationId,
            customerInfo,
            reservationDetails,
            status: "created"
          }));

          break;

        case ReservationStatusEnum.CONFIRMED:
          // Update reservation status
          yield* _(webhookService.updateReservationStatus(reservationId, "confirmed"));

          // Send confirmation to customer
          yield* _(emailService.sendCustomerReservationConfirmation({
            reservationId,
            customerInfo,
            reservationDetails
          }));

          break;

        case ReservationStatusEnum.DECLINED:
          // Update reservation status
          yield* _(webhookService.updateReservationStatus(reservationId, "declined"));

          // Send declined notification to customer
          yield* _(emailService.sendCustomerReservationDeclined({
            reservationId,
            customerInfo,
            reservationDetails
          }));

          break;

        default:
          return yield* _(E.fail(new WebhookProcessingError({
            message: `Unsupported reservation status: ${status}`,
            context: { reservationId, status }
          })));
      }

      return { success: true, reservationId, status };
    }).pipe(
      E.catchAll(error => 
        E.logError("Failed to process reservation webhook", { error }).pipe(
          E.flatMap(() => E.fail(new WebhookProcessingError({
            message: "Failed to process reservation webhook",
            cause: error
          })))
        )
      )
    )
};

/**
 * Create API route handler for reservation webhooks
 */
export const createReservationWebhookRouteHandler = () => {
  return async (req: Request) => {
    // Parse the request body
    const payload = await req.json();

    // Create the Effect program
    const program = E.gen(function* (_) {
      // Validate the webhook signature and payload
      const validationService = yield* _(WebhookValidationService);
      yield* _(validationService.validateWebhook(req, payload));

      // Process the reservation webhook
      return yield* _(ReservationWebhookHandler.processReservationStatusChange(payload));
    });

    // Run the program with all required layers
    const result = await E.runPromise(
      program.pipe(
        E.provide(WebhookServiceLive),
        E.provide(EmailServiceLive),
        E.provide(WebhookValidationServiceLive)
      )
    ).catch(error => {
      console.error("Webhook processing failed:", error);
      return { success: false, error: error.message };
    });

    return Response.json(result);
  };
};
```

