## Objective
Create a flexible webhook handler registry system that enables dynamic registration and routing of different webhook types, allowing for easy extension without modifying core application logic.

## Implementation Steps

1. **Create Webhook Handler Interface**:
```typescript
// backend/features/webhooks/interfaces/webhook-handler.interface.ts
import { Effect as E } from "effect";
import { WebhookPayload } from "../schemas/effect";

/**
 * Interface for all webhook handlers
 */
export interface WebhookHandler<T extends WebhookPayload = WebhookPayload> {
  /**
   * Unique identifier for this webhook type
   */
  readonly type: string;

  /**
   * Process the webhook payload
   */
  process(payload: T): E.Effect<never, Error, void>;

  /**
   * Validate if this handler can process the given payload
   */
  canHandle(payload: unknown): boolean;
}
```

2. **Implement Webhook Registry Service**:
```typescript
// backend/features/webhooks/services/webhook-registry.service.ts
import { Effect as E, Context } from "effect";
import { WebhookHandler } from "../interfaces/webhook-handler.interface";
import { WebhookHandlerNotFoundError } from "../errors/webhook-errors";

/**
 * Service for registering and retrieving webhook handlers
 */
export interface WebhookRegistryService {
  /**
   * Register a new webhook handler
   */
  registerHandler(handler: WebhookHandler): E.Effect<never, Error, void>;

  /**
   * Get a handler by webhook type
   */
  getHandler(type: string): E.Effect<never, WebhookHandlerNotFoundError, WebhookHandler>;

  /**
   * Find appropriate handler for a payload
   */
  findHandlerForPayload(payload: unknown): E.Effect<never, WebhookHandlerNotFoundError, WebhookHandler>;

  /**
   * Get all registered handlers
   */
  getAllHandlers(): E.Effect<never, never, ReadonlyArray<WebhookHandler>>;
}

/**
 * Context Tag for WebhookRegistryService
 */
export const WebhookRegistryService = Context.Tag<WebhookRegistryService>("WebhookRegistryService");

/**
 * Implementation of WebhookRegistryService
 */
export class WebhookRegistryServiceImpl implements WebhookRegistryService {
  private handlers: Map<string, WebhookHandler> = new Map();

  registerHandler(handler: WebhookHandler): E.Effect<never, Error, void> {
    return E.sync(() => {
      if (this.handlers.has(handler.type)) {
        return E.fail(new Error(`Handler for webhook type '${handler.type}' already registered`));
      }

      this.handlers.set(handler.type, handler);
    });
  }

  getHandler(type: string): E.Effect<never, WebhookHandlerNotFoundError, WebhookHandler> {
    return E.sync(() => {
      const handler = this.handlers.get(type);

      if (!handler) {
        return E.fail(new WebhookHandlerNotFoundError({ type }));
      }

      return handler;
    });
  }

  findHandlerForPayload(payload: unknown): E.Effect<never, WebhookHandlerNotFoundError, WebhookHandler> {
    return E.sync(() => {
      for (const handler of this.handlers.values()) {
        if (handler.canHandle(payload)) {
          return handler;
        }
      }

      return E.fail(new WebhookHandlerNotFoundError({ 
        message: "No handler found that can process this payload" 
      }));
    });
  }

  getAllHandlers(): E.Effect<never, never, ReadonlyArray<WebhookHandler>> {
    return E.succeed(Array.from(this.handlers.values()));
  }
}

/**
 * Layer for WebhookRegistryService
 */
export const WebhookRegistryServiceLive = Layer.succeed(
  WebhookRegistryService,
  new WebhookRegistryServiceImpl()
);
```

3. **Create Webhook Router Service**:
```typescript
// backend/features/webhooks/services/webhook-router.service.ts
import { Effect as E, Context, Layer } from "effect";
import { WebhookRegistryService } from "./webhook-registry.service";
import { WebhookValidationService } from "./webhook-validation.service";
import { WebhookProcessingError } from "../errors/webhook-errors";

/**
 * Service for routing webhook requests to appropriate handlers
 */
export interface WebhookRouterService {
  /**
   * Route a webhook request to the appropriate handler
   */
  routeWebhook(
    type: string | undefined,
    payload: unknown,
    signature: string | undefined
  ): E.Effect<never, Error, void>;
}

/**
 * Context Tag for WebhookRouterService
 */
export const WebhookRouterService = Context.Tag<WebhookRouterService>("WebhookRouterService");

/**
 * Implementation of WebhookRouterService
 */
export class WebhookRouterServiceImpl implements WebhookRouterService {
  constructor(
    private readonly registryService: WebhookRegistryService,
    private readonly validationService: WebhookValidationService
  ) {}

  routeWebhook(
    type: string | undefined,
    payload: unknown,
    signature: string | undefined
  ): E.Effect<never, Error, void> {
    return E.gen(function* (_) {
      // First validate the webhook
      const validatedPayload = yield* _(
        this.validationService.validateWebhook(payload, signature)
      );

      // Find the appropriate handler
      const handler = yield* _(
        type 
          ? this.registryService.getHandler(type)
          : this.registryService.findHandlerForPayload(validatedPayload)
      );

      // Process the webhook
      yield* _(
        handler.process(validatedPayload).pipe(
          E.catchAll(error => 
            E.fail(new WebhookProcessingError({
              message: `Error processing webhook of type '${handler.type}'`,
              cause: error
            }))
          )
        )
      );
    });
  }
}

/**
 * Layer for WebhookRouterService
 */
export const WebhookRouterServiceLive = Layer.effect(
  WebhookRouterService,
  E.gen(function* (_) {
    const registryService = yield* _(WebhookRegistryService);
    const validationService = yield* _(WebhookValidationService);

    return new WebhookRouterServiceImpl(registryService, validationService);
  })
);
```

4. **Update API Route to Use Registry System**:
```typescript
// app/api/webhooks/route.ts
import { NextRequest, NextResponse } from "next/server";
import { Effect as E } from "effect";
import { WebhookRouterService } from "@/backend/features/webhooks/services/webhook-router.service";
import { WebhookRegistryService } from "@/backend/features/webhooks/services/webhook-registry.service";
import { WebhookValidationService } from "@/backend/features/webhooks/services/webhook-validation.service";
import { ReservationWebhookHandler } from "@/backend/features/webhooks/handlers/reservation-webhook.handler";
import { logger } from "@/backend/lib/logger";

// Combine all required layers
const WebhookLayer = WebhookRouterServiceLive.pipe(
  Layer.provide(WebhookRegistryServiceLive),
  Layer.provide(WebhookValidationServiceLive)
);

export async function POST(request: NextRequest) {
  const signature = request.headers.get("x-webhook-signature") || undefined;
  const type = request.headers.get("x-webhook-type") || undefined;

  try {
    const payload = await request.json();

    const program = E.gen(function* (_) {
      // Get services from context
      const routerService = yield* _(WebhookRouterService);
      const registryService = yield* _(WebhookRegistryService);

      // Register handlers (in a real app, this would be done at startup)
      yield* _(registryService.registerHandler(new ReservationWebhookHandler()));

      // Route the webhook
      yield* _(routerService.routeWebhook(type, payload, signature));

      return { success: true };
    });

    const result = await E.runPromise(
      program.pipe(
        E.provide(WebhookLayer),
        E.catchAll(error => {
          logger.error("Webhook processing error", { error });
          return E.succeed({ success: false, error: error.message });
        })
      )
    );

    return NextResponse.json(result);
  } catch (error) {
    logger.error("Webhook request error", { error });
    return NextResponse.json(
      { success: false, error: "Invalid request" },
      { status: 400 }
    );
  }
}
