import { Effect as E } from "effect";
import { WebhookHandler } from "../interfaces/webhook-handler.interface";
import { WebhookPayload } from "../schemas/effect";

/**
 * Abstract base class for webhook handlers
 */
export abstract class BaseWebhookHandler<T extends WebhookPayload = WebhookPayload> 
  implements WebhookHandler<T> {

  /**
   * Unique identifier for this webhook type
   */
  abstract readonly type: string;

  /**
   * Process the webhook payload
   */
  abstract process(payload: T): E.Effect<never, Error, void>;

  /**
   * Validate if this handler can process the given payload
   * Override in subclasses for more specific logic
   */
  canHandle(payload: unknown): boolean {
    try {
      // Basic check if payload has a type field matching this handler
      if (typeof payload !== 'object' || payload === null) return false;

      const payloadWithType = payload as { type?: string };
      return payloadWithType.type === this.type;
    } catch {
      return false;
    }
  }
}
