```typescript
// app/api/webhooks/route.ts
import { NextRequest, NextResponse } from "next/server";
import { Effect as E } from "effect";
import { WebhookService } from "@/backend/features/webhooks/services/webhook-service";
import { WebhookValidationService } from "@/backend/features/webhooks/services/webhook-validation.service";
import { WebhookError, WebhookAuthenticationError, WebhookValidationError } from "@/backend/features/webhooks/errors/webhook-errors";

export async function POST(request: NextRequest) {
  // Extract webhook type from URL or headers
  const webhookType = request.headers.get("x-webhook-type") || "reservation";

  // Get raw body for signature validation
  const rawBody = await request.text();

  // Process webhook using Effect.ts pattern
  const result = await E.runPromise(
    E.flatMap(
      WebhookValidationService.validateWebhook({
        payload: rawBody,
        signature: request.headers.get("x-webhook-signature") || "",
        webhookType
      }),
      (validatedPayload) => WebhookService.processWebhook(webhookType, validatedPayload)
    ).pipe(
      E.catchTags({
        WebhookAuthenticationError: (error) => 
          E.succeed({ status: 401, body: { error: error.message } }),
        WebhookValidationError: (error) => 
          E.succeed({ status: 400, body: { error: error.message } }),
        WebhookProcessingError: (error) => 
          E.succeed({ status: 422, body: { error: error.message } }),
        WebhookError: (error) => 
          E.succeed({ status: 500, body: { error: "Failed to process webhook" } })
      }),
      E.catchAll((error) => 
        E.succeed({ status: 500, body: { error: "Unexpected error occurred" } })
      )
    )
  );

  return NextResponse.json(result.body, { status: result.status });
}
```

3. **Create Response Mapping Utility** (optional):
```typescript
// backend/features/webhooks/utils/response-mapper.ts
import { Effect as E } from "effect";
import { WebhookError, WebhookAuthenticationError, WebhookValidationError, WebhookProcessingError } from "../errors/webhook-errors";

export interface ApiResponse {
  status: number;
  body: Record<string, any>;
}

export const mapWebhookErrorToResponse = (error: unknown): E.Effect<never, never, ApiResponse> => {
  if (error instanceof WebhookAuthenticationError) {
    return E.succeed({ status: 401, body: { error: error.message } });
  } else if (error instanceof WebhookValidationError) {
    return E.succeed({ status: 400, body: { error: error.message } });
  } else if (error instanceof WebhookProcessingError) {
    return E.succeed({ status: 422, body: { error: error.message } });
  } else if (error instanceof WebhookError) {
    return E.succeed({ status: 500, body: { error: "Failed to process webhook" } });
  } else {
    return E.succeed({ status: 500, body: { error: "Unexpected error occurred" } });
  }
};
```

