import { logger } from "@/lib/logger";

export const WebhookLogger = {
  received: (webhookType: string, headers?: Record<string, any>) => {
    logger.info("Webhook received", { webhookType, headers });
  },
  processed: (webhookType: string, result?: any) => {
    logger.info("Webhook processed successfully", { webhookType, result });
  },
  failed: (webhookType: string, error: any) => {
    logger.error("Webhook processing failed", {
      webhookType,
      errorType: error._tag || typeof error,
      message: error.message,
      stack: process.env.NODE_ENV === "development" ? error.stack : undefined
    });
  },
  validationFailed: (webhookType: string, validationErrors: any) => {
    logger.warn("Webhook validation failed", { webhookType, validationErrors });
  }
};
