Update the route handler at `app/api/webhooks/route.ts` with the following implementation:

```typescript
import { NextRequest, NextResponse } from "next/server";
import { Effect as E } from "effect";
import { WebhookService } from "@/backend/features/webhooks/services/webhook-service";
import { WebhookValidationService } from "@/backend/features/webhooks/services/webhook-validation.service";
import { mapWebhookErrorToResponse } from "@/backend/features/webhooks/utils/response-mapper";
import { WebhookLogger } from "@/backend/features/webhooks/utils/webhook-logger";

export async function POST(request: NextRequest) {
  // Extract webhook type from URL or headers
  const webhookType = request.headers.get("x-webhook-type") || "reservation";

  // Log webhook receipt
  WebhookLogger.received(webhookType, Object.fromEntries(request.headers));

  // Get raw body for signature validation
  const rawBody = await request.text();

  // Process webhook using Effect.ts pattern
  const result = await E.runPromise(
    E.flatMap(
      WebhookValidationService.validateWebhook({
        payload: rawBody,
        signature: request.headers.get("x-webhook-signature") || "",
        webhookType
      }),
      (validatedPayload) => WebhookService.processWebhook(webhookType, validatedPayload)
    ).pipe(
      E.map((processResult) => {
        WebhookLogger.processed(webhookType, processResult);
        return { status: 200, body: { success: true, data: processResult } };
      }),
      E.catchAll((error) => {
        WebhookLogger.failed(webhookType, error);
        return mapWebhookErrorToResponse(error);
      })
    )
  );

  return NextResponse.json(result.body, { status: result.status });
}
```

