3. **Implement Tracing Middleware for Webhook Processing**:
```typescript
// backend/features/webhooks/middleware/tracing.middleware.ts
import { Effect as E, Tracer, Span } from "effect";
import { WebhookLoggerService } from "../services/webhook-logger.service";

/**
 * Middleware to add tracing to webhook processing
 */
export const withWebhookTracing = <R, E, A>(
  effect: E.Effect<R, E, A>,
  source: string,
  operation: string
): E.Effect<R | WebhookLoggerService, E, A> => {
  return E.gen(function* (_) {
    const logger = yield* _(WebhookLoggerService);

    // Create a span for the operation
    return yield* _(
      effect.pipe(
        Tracer.withSpan(`webhook.${source}.${operation}`, {
          attributes: {
            "webhook.source": source,
            "webhook.operation": operation
          }
        }),
        E.tap(() => logger.logWebhookProcessed(source, `${operation} completed`)),
        E.tapError((error) => logger.logWebhookError(source, error))
      )
    );
  });
};
```

