// app/api/webhooks/route.ts
import { NextRequest, NextResponse } from "next/server";
import { Effect as E, Tracer } from "effect";
import { WebhookService } from "@/backend/features/webhooks/services/webhook-service";
import { WebhookLoggerService } from "@/backend/features/webhooks/services/webhook-logger.service";
import { WebhookLoggingConfigLive, WebhookLoggerServiceLive } from "@/backend/features/webhooks/utils/logging";

export async function POST(request: NextRequest) {
  const source = request.headers.get("x-webhook-source") || "unknown";
  const signature = request.headers.get("x-webhook-signature");

  // Create the main effect with tracing
  const program = E.gen(function* (_) {
    const payload = yield* _(E.tryPromise(() => request.json()));
    const webhookService = yield* _(WebhookService);
    const logger = yield* _(WebhookLoggerService);

    yield* _(logger.logWebhookReceived(source, payload));

    // Process webhook with root span
    yield* _(
      webhookService.processWebhook(source, payload, signature).pipe(
        Tracer.withSpan(`webhook.${source}.request`, {
          attributes: {
            "webhook.source": source,
            "http.method": "POST",
            "http.url": request.url
          }
        })
      )
    );

    return NextResponse.json({ success: true });
  });

  // Run the effect with all required layers
  return await E.runPromise(
    program.pipe(
      E.catchAll((error) => {
        console.error("Webhook processing error:", error);
        return E.succeed(
          NextResponse.json(
            { success: false, error: error.message },
            { status: 500 }
          )
        );
      })
    ),
    {
      layer: WebhookLoggingConfigLive.pipe(
        Layer.provide(WebhookLoggerServiceLive),
        // Other required layers...
      )
    }
  );
}
```

