export const createStructuredLogger = () => {
  return Logger.make(({ logLevel, message, cause, context, date, annotations }) => {
    const logEntry = {
      timestamp: date.toISOString(),
      level: LogLevel.label(logLevel),
      message,
      context: context || undefined,
      annotations: annotations.size > 0 ? Object.fromEntries(annotations) : undefined,
      cause: cause ? E.prettyError(cause) : undefined
    };

