## Effect.ts Patterns

### Context.Tag Services
The webhook system uses Effect.ts Context.Tag pattern for dependency injection:

```typescript
// Example of WebhookService as a Context.Tag
export interface WebhookService {
  processWebhook(payload: WebhookPayload): Effect<never, WebhookError, void>;
}

export const WebhookService = Context.Tag<WebhookService>("WebhookService");

// Implementation
export class WebhookServiceLive implements WebhookService {
  processWebhook(payload: WebhookPayload): Effect<never, WebhookError, void> {
    return Effect.gen(function* (_) {
      const registry = WebhookRegistryService.getInstance();
      const handler = registry.getHandler(payload.type);

      if (!handler) {
        return yield* _(Effect.fail(new WebhookTypeNotFoundError(payload.type)));
      }

      return yield* _(handler.handle(payload.payload));
    });
  }
}

// Layer for providing the service
