### Error Handling
The webhook system uses tagged errors for precise error handling:

```typescript
// Base webhook error class
export class WebhookError extends Effect.TaggedError<"WebhookError">() {
  readonly _tag = "WebhookError";

  constructor(readonly message: string, readonly cause?: unknown) {
    super(message);
  }
}

// Specific error types
export class WebhookValidationError extends WebhookError {
  readonly _tag = "WebhookValidationError";

  constructor(readonly message: string, readonly cause?: unknown) {
    super(message, cause);
  }
}

export class WebhookTypeNotFoundError extends WebhookError {
  readonly _tag = "WebhookTypeNotFoundError";

  constructor(readonly type: string) {
    super(`No handler registered for webhook type '${type}'`);
  }
}

export class WebhookSignatureError extends WebhookError {
  readonly _tag = "WebhookSignatureError";

  constructor() {
    super("Invalid webhook signature");
  }
}
