## Objective
Implement Vercel's bot protection system across all forms in the application to prevent spam and automated bot submissions while maintaining a seamless user experience.

## Implementation Steps

1. **Install Required Dependencies**:
```bash
npm install @vercel/protection
```

2. **Create Bot Protection Provider**:
```tsx
// components/providers/bot-protection-provider.tsx
import { createContext, useContext, ReactNode } from 'react';
import { useVercelBotId } from '@vercel/protection';

interface BotProtectionContextType {
  getBotIdProps: () => { 'data-botid': string };
  isBot: boolean;
}

const BotProtectionContext = createContext<BotProtectionContextType | null>(null);

export function BotProtectionProvider({ children }: { children: ReactNode }) {
  const { botId, isBot } = useVercelBotId();

  const getBotIdProps = () => ({ 'data-botid': botId });

  return (
    <BotProtectionContext.Provider value={{ getBotIdProps, isBot }}>
      {children}
    </BotProtectionContext.Provider>
  );
}

export const useBotProtection = () => {
  const context = useContext(BotProtectionContext);
  if (!context) {
    throw new Error('useBotProtection must be used within a BotProtectionProvider');
  }
  return context;
};
```

3. **Add Provider to Root Layout**:
```tsx
// app/[locale]/layout.tsx
import { BotProtectionProvider } from '@/components/providers/bot-protection-provider';

export default function RootLayout({ children }) {
  return (
    <html lang="en">
      <body>
        <BotProtectionProvider>
          {/* Other providers */}
          {children}
        </BotProtectionProvider>
      </body>
    </html>
  );
}
```

4. **Create Form Protection Hook**:
```tsx
// hooks/use-form-protection.ts
import { useBotProtection } from '@/components/providers/bot-protection-provider';
import { useEffect, useState } from 'react';

export function useFormProtection() {
  const { getBotIdProps, isBot } = useBotProtection();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isProtected, setIsProtected] = useState(false);

  useEffect(() => {
    // Set protection status after initial render
    setIsProtected(true);
  }, []);

  const handleSubmit = async (callback: () => Promise<any>) => {
    if (isBot) {
      console.log('Bot submission prevented');
      return;
    }

    setIsSubmitting(true);
    try {
      await callback();
    } catch (error) {
      console.error('Form submission error:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return {
    botIdProps: getBotIdProps(),
    isBot,
    isSubmitting,
    isProtected,
    handleSubmit
  };
}
```

5. **Update Form Components to Use Bot Protection**:
```tsx
// components/ui/form.tsx
import { useFormProtection } from '@/hooks/use-form-protection';

export function Form({ onSubmit, children, ...props }) {
  const { botIdProps, handleSubmit, isSubmitting } = useFormProtection();

  const handleFormSubmit = async (e) => {
    e.preventDefault();
    await handleSubmit(() => onSubmit(e));
  };

  return (
    <form onSubmit={handleFormSubmit} {...botIdProps} {...props}>
      {children}
      {isSubmitting && <div className="form-loading-indicator">Submitting...</div>}
    </form>
  );
}
```

6. **Update Contact Form Implementation**:
