2. **Create Status-Based Message Variants**:
```typescript
// app/[locale]/reservation/[id]/status-messages.ts
import { createTranslator } from '@/paraglide/runtime';

export type ReservationStatus = 'pending' | 'confirmed' | 'declined';

export const getStatusMessages = (t: ReturnType<typeof createTranslator>, status: ReservationStatus) => {
  switch (status) {
    case 'confirmed':
      return {
        heading: t('reservation.status.confirmed.heading'),
        subheading: t('reservation.status.confirmed.subheading'),
        nextSteps: [
          t('reservation.status.confirmed.nextSteps.1'),
          t('reservation.status.confirmed.nextSteps.2'),
          t('reservation.status.confirmed.nextSteps.3')
        ]
      };
    case 'declined':
      return {
        heading: t('reservation.status.declined.heading'),
        subheading: t('reservation.status.declined.subheading'),
        nextSteps: [
          t('reservation.status.declined.nextSteps.1'),
          t('reservation.status.declined.nextSteps.2')
        ]
      };
    default:
      return {
        heading: t('reservation.status.pending.heading'),
        subheading: t('reservation.status.pending.subheading'),
        nextSteps: [
          t('reservation.status.pending.nextSteps.1'),
          t('reservation.status.pending.nextSteps.2')
        ]
      };
  }
};
